/**
 * Type Guard Utilities
 *
 * Runtime type checking for better type safety
 */
import type { InfiniteScrollConfig, PageBasedConfig, CursorBasedConfig } from "../types/infinite-scroll-config";
/**
 * Check if config is page-based pagination
 */
export declare function isPageBasedConfig<T>(config: InfiniteScrollConfig<T>): config is PageBasedConfig<T>;
/**
 * Check if config is cursor-based pagination
 */
export declare function isCursorBasedConfig<T>(config: InfiniteScrollConfig<T>): config is CursorBasedConfig<T>;
/**
 * Check if value is a valid error
 */
export declare function isError(value: unknown): value is Error;
/**
 * Check if value is a non-null object
 */
export declare function isNonNullObject<T>(value: T | null | undefined): value is T;
/**
 * Check if array has items
 */
export declare function hasItems<T>(items: T[] | null | undefined): items is T[];
/**
 * Check if string is not empty
 */
export declare function isNonEmptyString(value: string | null | undefined): value is string;
